mapper.select:
SELECT VNGL.GATE_CD , VNGL.VENDOR_CD , GETCOMPANYNAME(VNGL.GATE_CD, VNGL.VENDOR_CD, #{ses.langCd}) AS VENDOR_NM , VNGL.VENDOR_ENG_NM , VNGL.REG_TYPE , GETCOMCODE(VNGL.GATE_CD, 'M014', VNGL.REG_TYPE, '0', #{ses.langCd}) AS REG_TYPE_NM , VNGL.IRS_NO , VNGL.COMPANY_REG_NO , VNGL.HQ_ZIP_CD AS HQ_ZIP_CD , VNGL.HQ_ADDR_1 AS HQ_ADDR_1 , VNGL.HQ_ADDR_2 AS HQ_ADDR_2 , VNGL.CEO_USER_NM AS CEO_USER_NM , VNGL.BUSINESS_TYPE , VNGL.INDUSTRY_TYPE , (VNGL.FOUNDATION_DATE, 'YYYY-MM-DD') AS FOUNDATION_DATE , VNGL.TEL_NO AS TEL_NO , VNGL.FAX_NO AS FAX_NO , VNGL.EMAIL AS EMAIL , VNGL.BUSINESS_SIZE , GETCOMCODE(VNGL.GATE_CD, 'MP039', VNGL.BUSINESS_SIZE, '0', #{ses.langCd}) AS BUSINESS_SIZE_NM , VNGL.BUSINESS_DIVISION , GETCOMCODE(VNGL.GATE_CD, 'MP040', VNGL.BUSINESS_DIVISION, '0', #{ses.langCd}) AS BUSINESS_DIVISION_NM , '' AS REGION_CD , VNGL.BUSINESS_REMARK , VNGL.REMARK_TEXT , VNGL.RELAT_YN , GETCOMCODE(VNGL.GATE_CD, 'NH0005', VNGL.RELAT_YN, '0', #{ses.langCd}) AS RELAT_YN_NM , VNGL.CORP_TYPE , GETCOMCODE(VNGL.GATE_CD, 'NH0002', VNGL.CORP_TYPE, '0', #{ses.langCd}) AS CORP_TYPE_NM -- 재무정보 , VNFI.FI_YEAR , GETCOMCODE(VNGL.GATE_CD, 'M174', VNFI.FI_YEAR, '0', #{ses.langCd}) AS FI_YEAR_NM , VNFI.EVIDENCE_TYPE , GETCOMCODE(VNGL.GATE_CD, 'MP048', VNFI.EVIDENCE_TYPE, '0', #{ses.langCd}) AS EVIDENCE_TYPE_NM , VNFI.OWNER_CAPITAL_AMOUNT , VNFI.TOT_FUND_AMT , VNFI.TOT_LIAB_AMT , VNFI.TOTAL_LIABILITY_RATE , VNFI.CURRENT_ASSET_AMOUNT , VNFI.CURRENT_ASSET_LIABILITY_AMOUNT
, CASE WHEN NVL (VNFI.CURRENT_ASSET_LIABILITY_AMOUNT,1) = 0 THEN NULL ELSE ((VNFI.CURRENT_ASSET_AMOUNT,0) / (VNFI.CURRENT_ASSET_LIABILITY_AMOUNT,1)) * 100 END AS CURRENT_ASSET_LIABILITY_RATE
, VNFI.SALES_AMOUNT , VNFI.NET_PROFIT_AMOUNT , VNFI.ATT_FILE_NUM AS VNFI_ATT_FILE_NUM , CASE WHEN GETFILECOUNT(VNFI.GATE_CD, VNFI.ATT_FILE_NUM) = 0 THEN NULL ELSE GETFILECOUNT(VNFI.GATE_CD, VNFI.ATT_FILE_NUM) END AS VNFI_ATT_FILE_NUM_CNT -- 관리정보 , VNGL.CREDIT_EVAL_COMPANY , VNGL.CREDIT_CD , GETCOMCODE(VNGL.GATE_CD, 'MP003', VNGL.CREDIT_CD, '0', #{ses.langCd}) AS CREDIT_NM , VNGL.EV_ATT_FILE_NUM AS EV_ATT_FILE_NUM , CASE WHEN GETFILECOUNT(VNGL.GATE_CD, VNGL.EV_ATT_FILE_NUM) = 0 THEN NULL ELSE GETFILECOUNT(VNGL.GATE_CD, VNGL.EV_ATT_FILE_NUM) END AS EV_ATT_FILE_NUM_CNT , VNGL.E_BILL_ASP_TYPE , GETCOMCODE(VNGL.GATE_CD, 'MP075', VNGL.E_BILL_ASP_TYPE, '0', #{ses.langCd}) AS E_BILL_ASP_TYPE_NM , VNGL.TAX_ASP_NM , VNGL.TAX_SEND_TYPE , GETCOMCODE(VNGL.GATE_CD, 'MP064', VNGL.TAX_SEND_TYPE, '0', #{ses.langCd}) AS TAX_SEND_TYPE_NM , VNGL.BLOCK_FLAG , GETCOMCODE(VNGL.GATE_CD, 'MP006', VNGL.BLOCK_FLAG, '0', #{ses.langCd}) AS BLOCK_FLAG_NM , VNGL.BLOCK_REASON , VNGL.PROGRESS_CD , GETCOMCODE(VNGL.GATE_CD, 'M019', VNGL.PROGRESS_CD, '0', #{ses.langCd}) AS PROGRESS_NM , VNGL.SIGN_STATUS , GETCOMCODE(VNGL.GATE_CD, 'M019', VNGL.SIGN_STATUS, '0', #{ses.langCd}) AS SIGN_STATUS_NM , VNGL.MOD_USER_ID , GETUSERNAME(VNGL.GATE_CD, VNGL.MOD_USER_ID , #{ses.langCd}) AS MOD_USER_NM , (VNGL.MOD_DATE, 'YYYY-MM-DD HH24:MI') AS MOD_DATE , DBK.CLIP_GRD AS NICE_DB_GRD , INT.CR_GRD AS KED_GRD , (VNGL.REG_DATE, 'YYYY-MM-DD HH24:MI') AS REG_DATE -- 결제정보 , VNGL.PAY_CONDITION , GETCOMCODE(VNGL.GATE_CD, 'MP045', VNGL.PAY_CONDITION, '0', #{ses.langCd}) AS PAY_CONDITION_NM , VNGL.PAY_TYPE , GETCOMCODE(VNGL.GATE_CD, 'MP046', VNGL.PAY_TYPE, '0', #{ses.langCd}) AS PAY_TYPE_NM , VNGL.PAY_PUBLIC_TYPE , GETCOMCODE(VNGL.GATE_CD, 'MP047', VNGL.PAY_PUBLIC_TYPE, '0', #{ses.langCd}) AS PAY_PUBLIC_TYPE_NM , ( SELECT VNCM.CONFIRM_FLAG FROM STOCVNCM VNCM WHERE VNCM.GATE_CD = VNGL.GATE_CD AND VNCM.VENDOR_CD = VNGL.VENDOR_CD AND VNCM.BUYER_CD = #{ses.companyCd} AND VNCM.DEL_FLAG = '0') AS CONFIRM_FLAG FROM STOCVNGL VNGL LEFT JOIN STOCVNFI VNFI ON (VNFI.GATE_CD = VNGL.GATE_CD AND VNFI.VENDOR_CD = VNGL.VENDOR_CD AND VNFI.FI_YEAR = (SELECT MAX(FI_YEAR) FROM STOCVNFI S WHERE S.GATE_CD = VNFI.GATE_CD AND S.VENDOR_CD = VNFI.VENDOR_CD AND S.DEL_FLAG = '0')) LEFT JOIN ( SELECT DBK.BIZ_NO , DBK.CLIP_GRD , DBK.G_DATE FROM DBK_RPT01 DBK WHERE (SYSDATE, 'YYYYMMDD') >= DBK.G_DATE AND (SYSDATE, 'YYYYMMDD') <= DBK.EXP_DATE AND DBK.G_DATE = ( SELECT MAX(G_DATE) FROM DBK_RPT01 S WHERE S.BIZ_NO = DBK.BIZ_NO) ) DBK ON (VNGL.IRS_NO = DBK.BIZ_NO) LEFT JOIN INTR INT ON (VNGL.IRS_NO = INT.BZNO) WHERE VNGL.GATE_CD = #{ses.gateCd} AND VNGL.DEL_FLAG = '0' AND VNGL.VENDOR_CD = #{VENDOR_CD}

mapper.update:
UPDATE STOCVNCM SET
      CONFIRM_FLAG = 'E'
    , CONFIRM_USER_ID = #{ses.userId}
    , CONFIRM_DATE = SYSDATE
    , MOD_DATE = SYSDATE
    , MOD_USER_ID = #{ses.userId}
WHERE GATE_CD   = #{ses.gateCd}
  AND VENDOR_CD = #{VENDOR_CD}
  AND BUYER_CD  = #{ses.companyCd}

UPDATE STOCCVUR SET
      MNG_YN = '1'
    , PROGRESS_CD = 'E'
    , MOD_DATE = SYSDATE
    , MOD_USER_ID = #{ses.userId}
WHERE GATE_CD = #{ses.gateCd}
  AND COMPANY_CD = #{VENDOR_CD}

UPDATE STOCVNGL SET
      PROGRESS_CD = 'E'
    , MOD_DATE = SYSDATE
    , MOD_USER_ID = #{ses.userId}
WHERE GATE_CD = #{ses.gateCd}
  AND VENDOR_CD = #{VENDOR_CD}

UPDATE STOCVNCM SET
      CONFIRM_FLAG = 'R'
    , CONFIRM_USER_ID = #{ses.userId}
    , CONFIRM_REASON = #{CONFIRM_REASON}
    , CONFIRM_DATE = SYSDATE
    , MOD_DATE = SYSDATE
    , MOD_USER_ID = #{ses.userId}
WHERE GATE_CD   = #{ses.gateCd}
  AND VENDOR_CD = #{VENDOR_CD}
  AND BUYER_CD  = #{ses.companyCd}
